        return '''// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title RugMuncherCRM
 * @dev CRM 2.0 Token with advanced features
 */
contract RugMuncherCRM is ERC20, Ownable, ReentrancyGuard, Pausable {

    // Tax configuration
    uint256 public buyTax = 250; // 2.5% = 250 basis points
    uint256 public sellTax = 500; // 5%
    uint256 public transferTax = 0;
    uint256 public constant MAX_TAX = 1000; // 10% max

    // Tax distribution (must sum to 100%)
    uint256 public liquidityShare = 50;
    uint256 public marketingShare = 30;
    uint256 public burnShare = 10;
    uint256 public devShare = 10;

    // Anti-whale
    uint256 public maxWalletPercent = 200; // 2%
    uint256 public maxTxPercent = 100; // 1%
    bool public antiWhaleEnabled = true;

    // Addresses
    address public marketingWallet;
    address public devWallet;
    address public liquidityWallet;

    // Blacklist/whitelist
    mapping(address => bool) public blacklisted;
    mapping(address => bool) public whitelisted;

    // Trading enabled
    bool public tradingEnabled = false;

    // Events
    event TaxCollected(address indexed from, uint256 amount, string taxType);
    event Blacklisted(address indexed account, bool status);
    event Whitelisted(address indexed account, bool status);
    event TradingEnabled(bool enabled);

    constructor(
        string memory name,
        string memory symbol,
        uint256 initialSupply,
        address _marketingWallet,
        address _devWallet,
        address _liquidityWallet
    ) ERC20(name, symbol) {
        require(_marketingWallet != address(0), "Invalid marketing wallet");
        require(_devWallet != address(0), "Invalid dev wallet");

        marketingWallet = _marketingWallet;
        devWallet = _devWallet;
        liquidityWallet = _liquidityWallet;

        _mint(msg.sender, initialSupply * 10**decimals());
    }

    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal override whenNotPaused {
        require(!blacklisted[sender] && !blacklisted[recipient], "Blacklisted");

        if (antiWhaleEnabled && !whitelisted[recipient]) {
            require(
                balanceOf(recipient) + amount <= totalSupply() * maxWalletPercent / 10000,
                "Exceeds max wallet"
            );
        }

        uint256 taxAmount = 0;

        if (!whitelisted[sender] && !whitelisted[recipient]) {
            if (recipient == address(this)) {
                taxAmount = amount * sellTax / 10000;
            } else if (sender == address(this)) {
                taxAmount = amount * buyTax / 10000;
            } else {
                taxAmount = amount * transferTax / 10000;
            }
        }

        if (taxAmount > 0) {
            super._transfer(sender, address(this), taxAmount);
            _distributeTax(taxAmount);
        }

        super._transfer(sender, recipient, amount - taxAmount);
    }

    function _distributeTax(uint256 amount) internal {
        uint256 liquidityAmount = amount * liquidityShare / 100;
        uint256 marketingAmount = amount * marketingShare / 100;
        uint256 burnAmount = amount * burnShare / 100;
        uint256 devAmount = amount * devShare / 100;

        _transfer(address(this), liquidityWallet, liquidityAmount);
        _transfer(address(this), marketingWallet, marketingAmount);
        _burn(address(this), burnAmount);
        _transfer(address(this), devWallet, devAmount);
    }

    // Admin functions
    function setTaxes(uint256 _buy, uint256 _sell, uint256 _transfer) external onlyOwner {
        require(_buy <= MAX_TAX && _sell <= MAX_TAX && _transfer <= MAX_TAX, "Tax too high");
        buyTax = _buy;
        sellTax = _sell;
        transferTax = _transfer;
    }

    function setTaxDistribution(
        uint256 _liquidity,
        uint256 _marketing,
        uint256 _burn,
        uint256 _dev
    ) external onlyOwner {
        require(_liquidity + _marketing + _burn + _dev == 100, "Must sum to 100");
        liquidityShare = _liquidity;
        marketingShare = _marketing;
        burnShare = _burn;
        devShare = _dev;
    }

    function setBlacklist(address account, bool status) external onlyOwner {
        blacklisted[account] = status;
        emit Blacklisted(account, status);
    }

    function setWhitelist(address account, bool status) external onlyOwner {
        whitelisted[account] = status;
        emit Whitelisted(account, status);
    }

    function setAntiWhale(bool enabled, uint256 _maxWallet, uint256 _maxTx) external onlyOwner {
        antiWhaleEnabled = enabled;
        maxWalletPercent = _maxWallet;
        maxTxPercent = _maxTx;
    }

    function enableTrading() external onlyOwner {
        tradingEnabled = true;
        emit TradingEnabled(true);
    }

    function burn(uint256 amount) external {
        _burn(msg.sender, amount);
    }

    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function rescueTokens(address token, uint256 amount) external onlyOwner {
        require(token != address(this), "Cannot rescue self");
        IERC20(token).transfer(owner(), amount);
    }

    receive() external payable {}
}

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
}
'''

    def get_crm_contract_solana(self) -> str:
        """Get CRM 2.0 contract source for Solana (Anchor/Rust)"""
        return '''use anchor_lang::prelude::*;
use anchor_spl::token::{self, Token, TokenAccount, Mint, Transfer};

declare_id!("CRMTken1111111111111111111111111111111111111");

#[program]
pub mod rugmuncher_crm {
    use super::*;

    pub fn initialize(
        ctx: Context<Initialize>,
        name: String,
        symbol: String,
        decimals: u8,
        initial_supply: u64,
    ) -> Result<()> {
        let config = &mut ctx.accounts.config;
        config.authority = ctx.accounts.authority.key();
        config.mint = ctx.accounts.mint.key();
        config.name = name;
        config.symbol = symbol;
        config.initialized = true;

        // Default tax config
        config.buy_tax_bps = 250;  // 2.5%
        config.sell_tax_bps = 500; // 5%
        config.transfer_tax_bps = 0;

        // Tax distribution
        config.liquidity_share = 50;
        config.marketing_share = 30;
        config.burn_share = 10;
        config.dev_share = 10;

        // Anti-whale defaults (2% max wallet, 1% max tx)
        config.max_wallet_percent = 200;
        config.max_tx_percent = 100;
        config.anti_whale_enabled = true;

        // Transfer initial supply to authority
        token::mint_to(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                token::MintTo {
                    mint: ctx.accounts.mint.to_account_info(),
                    to: ctx.accounts.authority_token_account.to_account_info(),
                    authority: ctx.accounts.authority.to_account_info(),
                },
            ),
            initial_supply,
        )?;

        emit!(InitializeEvent {
            mint: ctx.accounts.mint.key(),
            authority: ctx.accounts.authority.key(),
            supply: initial_supply,
        });

        Ok(())
    }

    pub fn transfer(ctx: Context<TransferCtx>, amount: u64) -> Result<()> {
        let config = &ctx.accounts.config;

        // Check blacklist
        require!(
            !config.blacklisted.contains(&ctx.accounts.from.key()),
            ErrorCode::Blacklisted
        );
        require!(
            !config.blacklisted.contains(&ctx.accounts.to.key()),
            ErrorCode::Blacklisted
        );

        // Check whitelist for tax exemption
        let is_whitelisted = config.whitelisted.contains(&ctx.accounts.from.key()) 
            || config.whitelisted.contains(&ctx.accounts.to.key());

        let tax_amount = if is_whitelisted {
            0
        } else {
            // Determine tax rate (simplified - would check DEX in production)
            amount * config.transfer_tax_bps / 10000
        };

        // Execute transfer
        if tax_amount > 0 {
            // Transfer tax to treasury
            token::transfer(
                CpiContext::new(
                    ctx.accounts.token_program.to_account_info(),
                    Transfer {
                        from: ctx.accounts.from_token_account.to_account_info(),
                        to: ctx.accounts.treasury_account.to_account_info(),
                        authority: ctx.accounts.from.to_account_info(),
                    },
                ),
                tax_amount,
            )?;
        }

        // Transfer remaining amount
        token::transfer(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                Transfer {
                    from: ctx.accounts.from_token_account.to_account_info(),
                    to: ctx.accounts.to_token_account.to_account_info(),
                    authority: ctx.accounts.from.to_account_info(),
                },
            ),
            amount - tax_amount,
        )?;

        emit!(TransferEvent {
            from: ctx.accounts.from.key(),
            to: ctx.accounts.to.key(),
            amount,
            tax: tax_amount,
        });

        Ok(())
    }

    pub fn set_blacklist(
        ctx: Context<AdminCtx>,
        account: Pubkey,
        blacklisted: bool,
    ) -> Result<()> {
        let config = &mut ctx.accounts.config;

        if blacklisted {
            config.blacklisted.push(account);
        } else {
            config.blacklisted.retain(|&x| x != account);
        }

        emit!(BlacklistEvent { account, blacklisted });
        Ok(())
    }

    pub fn set_whitelist(
        ctx: Context<AdminCtx>,
        account: Pubkey,
        whitelisted: bool,
    ) -> Result<()> {
        let config = &mut ctx.accounts.config;

        if whitelisted {
            config.whitelisted.push(account);
        } else {
            config.whitelisted.retain(|&x| x != account);
        }

        emit!(WhitelistEvent { account, whitelisted });
        Ok(())
    }

    pub fn set_taxes(
        ctx: Context<AdminCtx>,
        buy_bps: u16,
        sell_bps: u16,
        transfer_bps: u16,
    ) -> Result<()> {
        require!(buy_bps <= 1000, ErrorCode::TaxTooHigh);
        require!(sell_bps <= 1000, ErrorCode::TaxTooHigh);
        require!(transfer_bps <= 1000, ErrorCode::TaxTooHigh);

        let config = &mut ctx.accounts.config;
        config.buy_tax_bps = buy_bps;
        config.sell_tax_bps = sell_bps;
        config.transfer_tax_bps = transfer_bps;

        emit!(TaxUpdateEvent {
            buy_bps,
            sell_bps,
            transfer_bps,
        });

        Ok(())
    }

    pub fn burn(ctx: Context<BurnCtx>, amount: u64) -> Result<()> {
        token::burn(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                token::Burn {
                    mint: ctx.accounts.mint.to_account_info(),
                    from: ctx.accounts.token_account.to_account_info(),
                    authority: ctx.accounts.authority.to_account_info(),
                },
            ),
            amount,
        )?;

        emit!(BurnEvent {
            account: ctx.accounts.authority.key(),
            amount,
        });

        Ok(())
    }
}

