        except Exception as e:
            logger.error(f"❌ Deployment failed: {e}")
            return DeploymentResult(
                success=False,
                contract_address=None,
                tx_hash=None,
                gas_used=None,
                block_number=None,
                verification_status="failed",
                error_message=str(e)
            )

    def deploy_crm_base(self, name: str, symbol: str, initial_supply: int,
                       marketing_wallet: str, dev_wallet: str, 
                       liquidity_wallet: str, deployer_key: str) -> DeploymentResult:
        """Deploy CRM 2.0 contract on Base"""
        config = DeploymentConfig(
            chain=Chain.BASE,
            contract_type=ContractType.CRM_20,
            name=name,
            symbol=symbol,
            initial_supply=initial_supply,
            auto_verify=True
        )

        # Save source code
        source = self.get_crm_contract_base()
        source_path = os.path.join(self.storage_path, "sources", f"CRM_{name}.sol")
        with open(source_path, 'w') as f:
            f.write(source)

        return self.deploy(config, deployer_key)

    def deploy_crm_solana(self, name: str, symbol: str, initial_supply: int,
                         deployer_key: str) -> DeploymentResult:
        """Deploy CRM 2.0 contract on Solana"""
        config = DeploymentConfig(
            chain=Chain.SOLANA,
            contract_type=ContractType.CRM_20,
            name=name,
            symbol=symbol,
            initial_supply=initial_supply,
            auto_verify=True
        )

        # Save source code
        source = self.get_crm_contract_solana()
        source_path = os.path.join(self.storage_path, "sources", f"CRM_{name}.rs")
        with open(source_path, 'w') as f:
            f.write(source)

        return self.deploy(config, deployer_key)

    def _save_deployment(self, deployment_id: str, config: DeploymentConfig, 
                        result: DeploymentResult):
        """Save deployment record"""
        record = {
            "id": deployment_id,
            "config": asdict(config),
            "result": asdict(result),
            "saved_at": datetime.now().isoformat()
        }

        path = os.path.join(self.storage_path, f"deployment_{deployment_id}.json")
        with open(path, 'w') as f:
            json.dump(record, f, indent=2)

    def _load_deployments(self):
        """Load existing deployments"""
        if not os.path.exists(self.storage_path):
            return

        for filename in os.listdir(self.storage_path):
            if filename.startswith("deployment_") and filename.endswith(".json"):
                try:
                    with open(os.path.join(self.storage_path, filename), 'r') as f:
                        data = json.load(f)
                    deployment_id = filename.replace("deployment_", "").replace(".json", "")
                    self.deployments[deployment_id] = DeploymentResult(**data["result"])
                except Exception as e:
                    logger.error(f"Failed to load {filename}: {e}")

    def get_deployment(self, deployment_id: str) -> Optional[Dict]:
        """Get deployment details"""
        path = os.path.join(self.storage_path, f"deployment_{deployment_id}.json")
        if os.path.exists(path):
            with open(path, 'r') as f:
                return json.load(f)
        return None

    def list_deployments(self, chain: Optional[str] = None) -> List[Dict]:
        """List all deployments"""
        results = []
        for filename in os.listdir(self.storage_path):
            if filename.startswith("deployment_") and filename.endswith(".json"):
                with open(os.path.join(self.storage_path, filename), 'r') as f:
                    data = json.load(f)
                    if chain is None or data["config"].get("chain") == chain:
                        results.append(data)
        return results


