#!/usr/bin/env python3
"""
🔧 RugMuncher Contract Deployer
Base & Solana smart contract deployment with automated verification
"""

import os
import json
import hashlib
import secrets
import logging
from datetime import datetime
from typing import Dict, List, Optional, Any
from dataclasses import dataclass, asdict
from enum import Enum

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Chain(Enum):
    BASE = "base"
    BASE_SEPOLIA = "base_sepolia"
    SOLANA = "solana"
    SOLANA_DEVNET = "solana_devnet"

class ContractType(Enum):
    CRM_20 = "crm_2.0"
    TOKEN_CUSTOM = "custom_token"
    MULTISIG = "multisig"
    PROXY = "proxy"

@dataclass
class DeploymentConfig:
    """Contract deployment configuration"""
    chain: Chain
    contract_type: ContractType
    name: str
    symbol: Optional[str] = None
    initial_supply: Optional[int] = None
    owner: Optional[str] = None

    # Verification settings
    auto_verify: bool = True
    verify_delay_seconds: int = 30

    # Security settings
    use_proxy: bool = False
    timelock_delay: int = 86400  # 24 hours

    # Gas settings
    max_fee_per_gas: Optional[int] = None
    priority_fee: Optional[int] = None

@dataclass
class DeploymentResult:
    """Result of contract deployment"""
    success: bool
    contract_address: Optional[str]
    tx_hash: Optional[str]
    gas_used: Optional[int]
    block_number: Optional[int]
    verification_status: str
    error_message: Optional[str] = None
    deployed_at: datetime = None

    def __post_init__(self):
        if self.deployed_at is None:
            self.deployed_at = datetime.now()

