    # Vesting
    vesting_enabled: bool = False
    vesting_duration_days: int = 365
    vesting_cliff_days: int = 90

    # Addresses
    marketing_wallet: str = ""
    dev_wallet: str = ""
    liquidity_wallet: str = ""

    def validate(self):
        """Validate configuration"""
        assert 0 <= self.buy_tax <= self.max_tax, f"Buy tax must be 0-{self.max_tax}%"
        assert 0 <= self.sell_tax <= self.max_tax, f"Sell tax must be 0-{self.max_tax}%"
        assert 0 <= self.transfer_tax <= self.max_tax, f"Transfer tax must be 0-{self.max_tax}%"

        total_tax_dist = (self.tax_to_liquidity + self.tax_to_marketing + 
                         self.tax_to_dev + self.tax_to_burn + self.tax_to_holders)
        assert abs(total_tax_dist - 100.0) < 0.01, "Tax distribution must sum to 100%"

        if self.mintable:
            assert self.max_supply is None or self.max_supply >= self.initial_supply

@dataclass
class AirdropConfig:
    """Airdrop configuration with safety features"""
    airdrop_type: str = "claim"  # claim, merkle, linear, vesting

    # Token settings
    token_address: str = ""
    total_airdrop_amount: int = 0

    # Claim settings
    claim_start_time: Optional[datetime] = None
    claim_end_time: Optional[datetime] = None
