    require_kyc: bool = False
    require_hold_duration: int = 0  # Days holding before claim

    # Emergency controls
    pausable: bool = True
    refundable: bool = True  # Allow reclaiming unclaimed tokens

    # Fee protection
    max_gas_price: int = 500  # Gwei - reject claims if gas too high

