    @staticmethod
    def get_erc20_tax(config: TokenConfig) -> str:
        """ERC20 with buy/sell/transfer taxes"""
        return f'''// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract {config.name.replace(" ", "")} is ERC20, Ownable, ReentrancyGuard {{

    // Tax configuration (basis points: 100 = 1%)
    uint256 public buyTax = {int(config.buy_tax * 100)};
    uint256 public sellTax = {int(config.sell_tax * 100)};
    uint256 public transferTax = {int(config.transfer_tax * 100)};
    uint256 public constant MAX_TAX = 1000; // 10% max

    // Tax distribution
    uint256 public liquidityShare = {int(config.tax_to_liquidity)};
    uint256 public marketingShare = {int(config.tax_to_marketing)};
    uint256 public devShare = {int(config.tax_to_dev)};
    uint256 public burnShare = {int(config.tax_to_burn)};

    // Addresses
    address public marketingWallet = {config.marketing_wallet or "address(0)"};
    address public devWallet = {config.dev_wallet or "address(0)"};
    address public liquidityWallet = {config.liquidity_wallet or "address(0)"};

    // Trading pairs
    mapping(address => bool) public isPair;

    {ContractTemplateLibrary._get_blacklist_vars(config)}
    {ContractTemplateLibrary._get_whitelist_vars(config)}
    {ContractTemplateLibrary._get_antiwhale_vars(config)}

    // Events
    event TaxCollected(address indexed from, uint256 amount, string taxType);
    event TaxUpdated(string taxType, uint256 newRate);

    constructor() ERC20("{config.name}", "{config.symbol}") {{
        _mint(msg.sender, {config.initial_supply} * 10 ** decimals());
    }}

    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal override nonReentrant {{
        require(sender != address(0), "Transfer from zero");
        require(recipient != address(0), "Transfer to zero");

        {ContractTemplateLibrary._get_blacklist_check(config)}
        {ContractTemplateLibrary._get_antiwhale_check(config)}

        uint256 taxAmount = 0;

        // Calculate tax
        if (!isWhitelisted(sender) && !isWhitelisted(recipient)) {{
            if (isPair[sender]) {{
                // Buying
                taxAmount = amount * buyTax / 10000;
            }} else if (isPair[recipient]) {{
                // Selling
                taxAmount = amount * sellTax / 10000;
            }} else {{
                // Transfer
                taxAmount = amount * transferTax / 10000;
            }}
        }}

        if (taxAmount > 0) {{
            super._transfer(sender, address(this), taxAmount);
            _distributeTax(taxAmount);
            emit TaxCollected(sender, taxAmount, 
                isPair[sender] ? "buy" : (isPair[recipient] ? "sell" : "transfer"));
        }}

        super._transfer(sender, recipient, amount - taxAmount);
    }}

    function _distributeTax(uint256 amount) internal {{
        uint256 liquidityAmount = amount * liquidityShare / 100;
        uint256 marketingAmount = amount * marketingShare / 100;
        uint256 devAmount = amount * devShare / 100;
        uint256 burnAmount = amount * burnShare / 100;

        if (liquidityAmount > 0 && liquidityWallet != address(0)) {{
            super._transfer(address(this), liquidityWallet, liquidityAmount);
        }}
        if (marketingAmount > 0 && marketingWallet != address(0)) {{
            super._transfer(address(this), marketingWallet, marketingAmount);
        }}
        if (devAmount > 0 && devWallet != address(0)) {{
            super._transfer(address(this), devWallet, devAmount);
        }}
        if (burnAmount > 0) {{
            _burn(address(this), burnAmount);
        }}
    }}

    // Admin functions
    function setTaxes(uint256 _buy, uint256 _sell, uint256 _transfer) external onlyOwner {{
        require(_buy <= MAX_TAX && _sell <= MAX_TAX && _transfer <= MAX_TAX, "Tax too high");
        buyTax = _buy;
        sellTax = _sell;
        transferTax = _transfer;
        emit TaxUpdated("all", _buy);
    }}

    function setTaxDistribution(
        uint256 _liquidity,
        uint256 _marketing,
        uint256 _dev,
        uint256 _burn
    ) external onlyOwner {{
        require(_liquidity + _marketing + _dev + _burn == 100, "Must sum to 100");
        liquidityShare = _liquidity;
        marketingShare = _marketing;
        devShare = _dev;
        burnShare = _burn;
    }}

    function setWallets(
        address _marketing,
        address _dev,
        address _liquidity
    ) external onlyOwner {{
        marketingWallet = _marketing;
        devWallet = _dev;
        liquidityWallet = _liquidity;
    }}

    function setPair(address pair, bool status) external onlyOwner {{
        isPair[pair] = status;
    }}

    {ContractTemplateLibrary._get_blacklist_functions(config)}
    {ContractTemplateLibrary._get_whitelist_functions(config)}
    {ContractTemplateLibrary._get_antiwhale_functions(config)}
    {ContractTemplateLibrary._get_rescue_function()}
}}'''

    @staticmethod
    def get_airdrop_claim(config: TokenConfig, airdrop: AirdropConfig) -> str:
        """Secure airdrop claim contract with anti-drain protection"""
        return f'''// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";

/**
 * @title SecureAirdrop
 * @dev Secure airdrop with anti-drain protection
 */
contract SecureAirdrop is Ownable, Pausable, ReentrancyGuard {{

    IERC20 public token;

    // Merkle root for eligibility
    bytes32 public merkleRoot;

    // Timing
    uint256 public claimStartTime;
    uint256 public claimEndTime;
    uint256 public claimCooldown = {airdrop.claim_cooldown_hours * 3600};

    // Limits
    uint256 public maxClaimPerWallet = {airdrop.max_claim_per_wallet};
    uint256 public minTokenBalance = {airdrop.min_token_balance_to_claim};

    // Anti-drain: max gas price
    uint256 public maxGasPrice = {airdrop.max_gas_price} gwei;

    // Tracking
    mapping(address => uint256) public claimedAmount;
    mapping(address => uint256) public claimCount;
    mapping(address => uint256) public lastClaimTime;
    uint256 public totalClaimed;

    // Refund
    bool public refundable = {str(airdrop.refundable).lower()};
    uint256 public unclaimedRefundTime;

    // Emergency recovery
    mapping(address => bool) public blockedWallets;

    // Events
    event Claimed(address indexed claimant, uint256 amount);
    event Blocked(address indexed wallet);
    event Unblocked(address indexed wallet);
    event EmergencyWithdrawn(uint256 amount);

    modifier validClaim() {{
        // Check gas price (anti-drain)
        require(tx.gasprice <= maxGasPrice, "Gas price too high");

        // Check timing
        require(block.timestamp >= claimStartTime, "Claim not started");
        require(block.timestamp <= claimEndTime, "Claim ended");

        // Check cooldown
        require(
            block.timestamp >= lastClaimTime[msg.sender] + claimCooldown,
            "Claim cooldown active"
        );

        // Check blocklist
        require(!blockedWallets[msg.sender], "Wallet blocked");

        // Check balance requirement
        require(token.balanceOf(msg.sender) >= minTokenBalance, "Insufficient balance");

        _;
    }}

    constructor(
        address _token,
        bytes32 _merkleRoot,
        uint256 _startTime,
        uint256 _endTime
    ) {{
        token = IERC20(_token);
        merkleRoot = _merkleRoot;
        claimStartTime = _startTime;
        claimEndTime = _endTime;
        unclaimedRefundTime = _endTime + 30 days;
    }}

    /**
     * @dev Claim airdrop with Merkle proof
     */
    function claim(
        uint256 amount,
        bytes32[] calldata merkleProof
    ) external whenNotPaused nonReentrant validClaim {{
        require(claimCount[msg.sender] < maxClaimPerWallet, "Max claims reached");

        // Verify merkle proof
        bytes32 leaf = keccak256(abi.encodePacked(msg.sender, amount));
        require(MerkleProof.verify(merkleProof, merkleRoot, leaf), "Invalid proof");

        // Check not already claimed full amount
        require(claimedAmount[msg.sender] < amount, "Already claimed");

        uint256 claimable = amount - claimedAmount[msg.sender];

        // Update state BEFORE transfer (checks-effects-interactions)
        claimedAmount[msg.sender] = amount;
        claimCount[msg.sender]++;
        lastClaimTime[msg.sender] = block.timestamp;
        totalClaimed += claimable;

        // Transfer with anti-reentrancy
        require(token.transfer(msg.sender, claimable), "Transfer failed");

        emit Claimed(msg.sender, claimable);
    }}

    /**
     * @dev Batch check eligibility (view function, no gas cost)
     */
    function checkEligibility(
        address account,
        uint256 amount,
        bytes32[] calldata merkleProof
    ) external view returns (bool) {{
        if (blockedWallets[account]) return false;
        if (block.timestamp < claimStartTime) return false;
        if (block.timestamp > claimEndTime) return false;

        bytes32 leaf = keccak256(abi.encodePacked(account, amount));
        return MerkleProof.verify(merkleProof, merkleRoot, leaf);
    }}

    /**
     * @dev Get claim status for an account
     */
    function getClaimStatus(address account) external view returns (
        uint256 claimed,
        uint256 claimCount_,
        uint256 nextClaimTime,
        bool canClaim
    ) {{
        claimed = claimedAmount[account];
        claimCount_ = claimCount[account];
        nextClaimTime = lastClaimTime[account] + claimCooldown;
        canClaim = (
            !blockedWallets[account] &&
            block.timestamp >= claimStartTime &&
            block.timestamp <= claimEndTime &&
            block.timestamp >= nextClaimTime &&
            claimCount[account] < maxClaimPerWallet
        );
    }}

    // Admin functions

    function setBlocked(address wallet, bool blocked) external onlyOwner {{
        blockedWallets[wallet] = blocked;
        if (blocked) {{
            emit Blocked(wallet);
        }} else {{
            emit Unblocked(wallet);
        }}
    }}

    function setMaxGasPrice(uint256 _maxGasPrice) external onlyOwner {{
        maxGasPrice = _maxGasPrice;
    }}

    function setClaimWindow(uint256 _start, uint256 _end) external onlyOwner {{
        claimStartTime = _start;
        claimEndTime = _end;
    }}

    function setMerkleRoot(bytes32 _merkleRoot) external onlyOwner {{
        merkleRoot = _merkleRoot;
    }}

    /**
     * @dev Emergency withdraw unclaimed tokens after claim period + buffer
     */
    function emergencyWithdraw() external onlyOwner {{
        require(refundable, "Not refundable");
        require(block.timestamp > unclaimedRefundTime, "Too early");

        uint256 balance = token.balanceOf(address(this));
        require(token.transfer(owner(), balance), "Withdraw failed");

        emit EmergencyWithdrawn(balance);
    }}

    /**
     * @dev Pause claims in emergency
     */
    function pause() external onlyOwner {{
        _pause();
    }}

    function unpause() external onlyOwner {{
        _unpause();
    }}

    /**
     * @dev Recover accidentally sent ERC20 tokens
     */
    function recoverERC20(address _token, uint256 amount) external onlyOwner {{
        require(_token != address(token), "Cannot recover airdrop token");
        require(IERC20(_token).transfer(owner(), amount), "Recover failed");
    }}
}}'''

    # ============== Helper Functions ==============

    @staticmethod
    def _get_mint_function(config: TokenConfig) -> str:
        if not config.mintable:
            return ""
        return '''
    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }'''

    @staticmethod
    def _get_burn_function(config: TokenConfig) -> str:
        if not config.burnable:
            return ""
        return '''
    function burn(uint256 amount) external {
        _burn(msg.sender, amount);
    }

    function burnFrom(address account, uint256 amount) external {
        _spendAllowance(account, msg.sender, amount);
        _burn(account, amount);
    }'''

    @staticmethod
    def _get_blacklist_vars(config: TokenConfig) -> str:
        if not config.blacklist_enabled:
            return ""
        return '''
    mapping(address => bool) public blacklisted;
    bool public blacklistEnabled = true;'''

    @staticmethod
    def _get_blacklist_check(config: TokenConfig) -> str:
        if not config.blacklist_enabled:
            return ""
        return '''
        require(!blacklisted[sender] && !blacklisted[recipient], "Blacklisted");'''

    @staticmethod
    def _get_blacklist_functions(config: TokenConfig) -> str:
        if not config.blacklist_enabled:
            return ""
        return '''
    function setBlacklisted(address account, bool status) external onlyOwner {
        blacklisted[account] = status;
    }

    function setBlacklistEnabled(bool enabled) external onlyOwner {
        blacklistEnabled = enabled;
    }'''

    @staticmethod
    def _get_whitelist_vars(config: TokenConfig) -> str:
        if not config.whitelist_enabled:
            return ""
        return '''
    mapping(address => bool) public whitelisted;'''

    @staticmethod
    def _get_whitelist_functions(config: TokenConfig) -> str:
        if not config.whitelist_enabled:
            return ""
        return '''
    function setWhitelisted(address account, bool status) external onlyOwner {
        whitelisted[account] = status;
    }

    function isWhitelisted(address account) public view returns (bool) {
        return whitelisted[account];
    }'''

    @staticmethod
    def _get_antiwhale_vars(config: TokenConfig) -> str:
        if not config.anti_whale_enabled:
            return ""
        return f'''
    uint256 public maxWalletAmount = {config.initial_supply} * {config.max_wallet_percent} / 100 * 10 ** decimals();
    uint256 public maxTxAmount = {config.initial_supply} * {config.max_tx_percent} / 100 * 10 ** decimals();
    bool public antiWhaleEnabled = true;'''

    @staticmethod
    def _get_antiwhale_check(config: TokenConfig) -> str:
        if not config.anti_whale_enabled:
            return ""
        return '''
        if (antiWhaleEnabled && !isWhitelisted(recipient)) {
            require(balanceOf(recipient) + amount <= maxWalletAmount, "Exceeds max wallet");
            require(amount <= maxTxAmount, "Exceeds max transaction");
        }'''

    @staticmethod
    def _get_antiwhale_functions(config: TokenConfig) -> str:
        if not config.anti_whale_enabled:
            return ""
        return '''
    function setAntiWhale(bool enabled, uint256 maxWallet, uint256 maxTx) external onlyOwner {
        antiWhaleEnabled = enabled;
        maxWalletAmount = maxWallet;
        maxTxAmount = maxTx;
    }'''

    @staticmethod
    def _get_rescue_function() -> str:
        return '''
    function rescueERC20(address token_, uint256 amount) external onlyOwner {
        require(token_ != address(this), "Cannot rescue self");
        IERC20(token_).transfer(owner(), amount);
    }

    function rescueETH() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }'''


class ContractBuilder:
    """Build contracts with custom configurations"""

    def __init__(self):
        self.token_config = TokenConfig(name="", symbol="")
        self.airdrop_config = AirdropConfig()
        self.template = ContractTemplate.ERC20_STANDARD
        self.chain = Chain.BASE

    def on_chain(self, chain: Chain) -> 'ContractBuilder':
        self.chain = chain
        return self

    def with_name(self, name: str, symbol: str) -> 'ContractBuilder':
        self.token_config.name = name
        self.token_config.symbol = symbol
        return self

    def with_supply(self, initial: int, max: Optional[int] = None) -> 'ContractBuilder':
        self.token_config.initial_supply = initial
        self.token_config.max_supply = max
        return self

    def with_decimals(self, decimals: int) -> 'ContractBuilder':
        self.token_config.decimals = decimals
        return self

    def mintable(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.mintable = enabled
        return self

    def burnable(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.burnable = enabled
        return self

    def pausable(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.pausable = enabled
        return self

    def upgradeable(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.upgradeable = enabled
        return self

    def with_taxes(self, buy: float = 0, sell: float = 0, transfer: float = 0) -> 'ContractBuilder':
        self.token_config.buy_tax = buy
        self.token_config.sell_tax = sell
        self.token_config.transfer_tax = transfer
        return self

    def with_tax_distribution(self, liquidity: float = 50, marketing: float = 30,
                              dev: float = 10, burn: float = 10, holders: float = 0) -> 'ContractBuilder':
        self.token_config.tax_to_liquidity = liquidity
        self.token_config.tax_to_marketing = marketing
        self.token_config.tax_to_dev = dev
        self.token_config.tax_to_burn = burn
        self.token_config.tax_to_holders = holders
        return self

    def with_blacklist(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.blacklist_enabled = enabled
        return self

    def with_whitelist(self, enabled: bool = True) -> 'ContractBuilder':
        self.token_config.whitelist_enabled = enabled
        return self

    def with_anti_whale(self, max_wallet_percent: float = 2.0, 
                       max_tx_percent: float = 1.0) -> 'ContractBuilder':
        self.token_config.anti_whale_enabled = True
        self.token_config.max_wallet_percent = max_wallet_percent
        self.token_config.max_tx_percent = max_tx_percent
        return self

    def with_vesting(self, duration_days: int = 365, cliff_days: int = 90) -> 'ContractBuilder':
        self.token_config.vesting_enabled = True
        self.token_config.vesting_duration_days = duration_days
        self.token_config.vesting_cliff_days = cliff_days
        return self

    def with_wallets(self, marketing: str = "", dev: str = "", liquidity: str = "") -> 'ContractBuilder':
        self.token_config.marketing_wallet = marketing
        self.token_config.dev_wallet = dev
        self.token_config.liquidity_wallet = liquidity
        return self

    def with_airdrop(self, total_amount: int, claim_type: str = "claim") -> 'ContractBuilder':
        self.airdrop_config.total_airdrop_amount = total_amount
        self.airdrop_config.airdrop_type = claim_type
        self.template = ContractTemplate.AIRDROP_CLAIM
        return self

    def with_airdrop_safety(self, max_gas_gwei: int = 500, 
                           cooldown_hours: int = 0,
                           require_hold_days: int = 0) -> 'ContractBuilder':
        self.airdrop_config.max_gas_price = max_gas_gwei
        self.airdrop_config.claim_cooldown_hours = cooldown_hours
        self.airdrop_config.require_hold_duration = require_hold_days
        return self

    def as_template(self, template: ContractTemplate) -> 'ContractBuilder':
        self.template = template
        return self

    def build(self) -> Dict[str, Any]:
        """Build and validate configuration"""
        self.token_config.validate()

        return {
            "chain": self.chain,
            "template": self.template,
            "token_config": asdict(self.token_config),
            "airdrop_config": asdict(self.airdrop_config) if self.template.value.startswith("airdrop") else None
        }

    def generate_contract(self) -> str:
        """Generate Solidity source code"""
        library = ContractTemplateLibrary()

        if self.template == ContractTemplate.ERC20_STANDARD:
            return library.get_erc20_standard(self.token_config)
        elif self.template == ContractTemplate.ERC20_TAX:
            return library.get_erc20_tax(self.token_config)
        elif self.template == ContractTemplate.AIRDROP_CLAIM:
            return library.get_airdrop_claim(self.token_config, self.airdrop_config)
        else:
            # Default to standard
            return library.get_erc20_standard(self.token_config)


class ContractDeployer:
    """Deploy contracts to blockchain"""

    def __init__(self, storage_path: str = "/root/rmi/contracts"):
        self.storage_path = storage_path
        os.makedirs(storage_path, exist_ok=True)
        os.makedirs(os.path.join(storage_path, "sources"), exist_ok=True)
        os.makedirs(os.path.join(storage_path, "abis"), exist_ok=True)

    def save_contract(self, name: str, source_code: str, chain: Chain) -> str:
        """Save contract source to disk"""
        filename = f"{name}_{chain.value}_{secrets.token_hex(4)}.sol"
        path = os.path.join(self.storage_path, "sources", filename)

        with open(path, 'w') as f:
            f.write(source_code)

        return path

    def compile_contract(self, source_path: str) -> Dict:
        """
        Compile contract using solc
        In production, this would actually compile
        """
        logger.info(f"Compiling {source_path}...")

        # Mock compilation result
        return {
            "abi": [],
            "bytecode": "0x" + secrets.token_hex(1000),
            "compiler_version": "0.8.19",
            "success": True
        }

    def deploy(self, build_config: Dict, deployer_key: str) -> Dict:
        """
        Deploy contract to blockchain
        Returns deployment info
        """
        chain = build_config["chain"]
        token_config = build_config["token_config"]

        # Generate contract
        builder = ContractBuilder()
        builder.chain = chain
        builder.token_config = TokenConfig(**token_config)

        source_code = builder.generate_contract()

        # Save source
        source_path = self.save_contract(
            token_config["name"].replace(" ", ""),
            source_code,
            chain
        )

        # Mock deployment
        deployment = {
            "contract_address": "0x" + secrets.token_hex(20) if "base" in chain.value else secrets.token_hex(32)[:44],
            "tx_hash": "0x" + secrets.token_hex(32),
            "block_number": secrets.randbelow(10000000),
            "gas_used": secrets.randbelow(5000000),
            "source_path": source_path,
            "chain": chain.value,
            "name": token_config["name"],
            "symbol": token_config["symbol"],
            "deployed_at": datetime.now().isoformat()
        }

        # Save deployment record
        record_path = os.path.join(
            self.storage_path,
            f"deployment_{deployment['contract_address']}.json"
        )
        with open(record_path, 'w') as f:
            json.dump(deployment, f, indent=2)

        logger.info(f"Deployed {token_config['name']} to {deployment['contract_address']}")

        return deployment


